import csv
from datetime import datetime

with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    rows = list(reader)

# Find unresolved questions
upcoming = []
for r in rows:
    if r['is_resolved'] == 'False':
        try:
            res_date = datetime.strptime(r['resolution_date'], '%Y-%m-%d')
            if res_date <= datetime(2026, 3, 10):
                upcoming.append(r)
        except:
            pass

for r in sorted(upcoming, key=lambda x: x['resolution_date']):
    title = r['title'][:80]
    print(f\"qid {r['qid']}: {title}... | Res: {r['resolution_date']}\")
